const fetch = require('node-fetch');

const CONFIG_COOKIE = '';
const CONFIG_AUTHORIZATION = '';
const CONFIG_HEADERS = {};
const SPIDER_API_KEY = '';
const MAX_TEXT_LENGTH = 12000;
const MIN_USEFUL_TEXT_LENGTH = 300;

const rawUrl = typeof $url === 'undefined' ? '' : String($url || '').trim();
const mode = (typeof $mode === 'undefined' ? 'auto' : String($mode || 'auto')).trim().toLowerCase();
const inputCookie = typeof $cookie === 'undefined' ? '' : String($cookie || '').trim();
const inputAuthorization = typeof $authorization === 'undefined' ? '' : String($authorization || '').trim();
const inputHeadersJson = typeof $headersJson === 'undefined' ? '' : String($headersJson || '').trim();

const normalizeUrl = (value) => {
    if (!value) throw new Error('请提供要抓取的 URL');
    const withProtocol = /^https?:\/\//i.test(value) ? value : `https://${value}`;
    const parsed = new URL(withProtocol);
    if (!['http:', 'https:'].includes(parsed.protocol)) throw new Error('只支持 http/https URL');
    return parsed.toString();
};

const truncate = (text, max = MAX_TEXT_LENGTH) => {
    const value = String(text || '').trim();
    return value.length > max ? `${value.slice(0, max)}\n...（内容过长已截断）` : value;
};

const parseHeaders = (raw) => {
    if (!raw) return {};
    try {
        const parsed = JSON.parse(raw);
        if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) throw new Error('headersJson 必须是对象');
        return Object.fromEntries(Object.entries(parsed).map(([key, value]) => [key, String(value)]));
    } catch (error) {
        throw new Error(`headersJson 解析失败：${error.message || String(error)}`);
    }
};

const buildHeaders = () => {
    const headers = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124 Safari/537.36 FlowOpsAuthorizedScraper/1.0',
        Accept: 'text/html,application/xhtml+xml,application/xml;q=0.9,text/plain;q=0.8,*/*;q=0.7',
        'Accept-Language': 'zh-CN,zh;q=0.9,en;q=0.8',
        ...CONFIG_HEADERS,
        ...parseHeaders(inputHeadersJson)
    };
    const cookie = inputCookie || CONFIG_COOKIE;
    const authorization = inputAuthorization || CONFIG_AUTHORIZATION;
    if (cookie) headers.Cookie = cookie.replace(/[\r\n]/g, ' ');
    if (authorization) headers.Authorization = authorization.replace(/[\r\n]/g, ' ');
    return headers;
};

const extractPage = (html, finalUrl) => {
    const titleMatch = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
    const descMatch = html.match(/<meta[^>]+(?:name|property)=["'](?:description|og:description|twitter:description)["'][^>]+content=["']([^"']*)["']/i);
    const links = [];
    html.replace(/<a\s+[^>]*href=["']([^"']+)["'][^>]*>/gi, (_match, href) => {
        try {
            const absolute = new URL(href, finalUrl).toString();
            if (absolute.startsWith('http') && !links.includes(absolute)) links.push(absolute);
        } catch (_error) {}
        return _match;
    });
    const text = html
        .replace(/<script[\s\S]*?<\/script>/gi, ' ')
        .replace(/<style[\s\S]*?<\/style>/gi, ' ')
        .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
        .replace(/<[^>]+>/g, ' ')
        .replace(/&nbsp;/g, ' ')
        .replace(/&amp;/g, '&')
        .replace(/&lt;/g, '<')
        .replace(/&gt;/g, '>')
        .replace(/&quot;/g, '"')
        .replace(/&#39;/g, "'")
        .replace(/\s+/g, ' ')
        .trim();
    return {
        title: titleMatch ? titleMatch[1].replace(/\s+/g, ' ').trim() : '',
        description: descMatch ? descMatch[1].trim() : '',
        text: truncate(text),
        links: links.slice(0, 50)
    };
};

const looksLikeLogin = (status, finalUrl, html, text) => {
    const sample = `${finalUrl}\n${html.slice(0, 4000)}\n${text.slice(0, 1000)}`.toLowerCase();
    return status === 401 || status === 403 || /login|sign[ -]?in|log in|oauth|authenticate|authentication|required to sign|unauthorized|forbidden|captcha|验证码|登录|请先登录|未登录|未授权|无权限|访问受限/.test(sample);
};

const fetchHttp = async (targetUrl, headers) => {
    const response = await fetch(targetUrl, { method: 'GET', headers, redirect: 'follow', timeout: 30000 });
    const finalUrl = response.url || targetUrl;
    const contentType = response.headers.get('content-type') || '';
    const body = await response.text();
    const extracted = contentType.includes('html') || body.includes('<html') ? extractPage(body, finalUrl) : { title: '', description: '', text: truncate(body), links: [] };
    return { ok: response.ok, status: response.status, statusText: response.statusText, url: finalUrl, contentType, html: body, ...extracted };
};

const fetchWithSpider = async (targetUrl) => {
    if (!SPIDER_API_KEY || SPIDER_API_KEY === 'SPIDER_API_KEY') {
        return { error: 'render 模式需要先在工具代码中配置 SPIDER_API_KEY。也可以提供 Cookie/Authorization 后使用 http/auto 模式。' };
    }
    const response = await fetch('https://api.spider.cloud/crawl', {
        method: 'POST',
        headers: { Authorization: `Bearer ${SPIDER_API_KEY}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ url: targetUrl, depth: 1, limit: 1, proxy_enabled: true, anti_bot: true, request: 'smart', return_format: 'text', cache: true })
    });
    const text = await response.text();
    if (!response.ok) return { error: `渲染抓取失败：${response.status} ${response.statusText} ${text}` };
    return { title: '', description: '', text: truncate(text), links: [] };
};

try {
    const targetUrl = normalizeUrl(rawUrl);
    const headers = buildHeaders();
    const hasAuth = !!(headers.Cookie || headers.Authorization);
    if (mode === 'render') {
        return JSON.stringify({ url: targetUrl, mode: 'render', result: await fetchWithSpider(targetUrl) }, null, 2);
    }
    const first = await fetchHttp(targetUrl, headers);
    const needsLogin = looksLikeLogin(first.status, first.url, first.html || '', first.text || '');
    if (needsLogin && !hasAuth) {
        return '页面需要登录或授权。请只在你有权访问该页面时提供自己的 Cookie、Authorization 或 headersJson；本工具不会绕过未授权访问、破解验证码或访问无权限内容。';
    }
    if ((!first.ok || (mode === 'auto' && (first.text || '').length < MIN_USEFUL_TEXT_LENGTH)) && SPIDER_API_KEY) {
        const rendered = await fetchWithSpider(targetUrl);
        return JSON.stringify({ url: targetUrl, mode: 'auto', strategy: 'render_fallback', status: first.status, result: rendered }, null, 2);
    }
    return JSON.stringify({ url: first.url, mode: 'http', status: first.status, title: first.title, description: first.description, text: first.text, links: first.links }, null, 2);
} catch (error) {
    return `网页抓取失败：${error.message || String(error)}`;
}
